-- ============================================================
-- ai-engineer-roadmap-sh-full-detailed-seed-v2-skill-conflict-fixed.sql
-- Full detailed AI Engineer roadmap seed based on roadmap.sh/ai-engineer.
-- Idempotent seed: safe to rerun in the same database/session.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap WHERE title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed');

    'AI Engineer',
    'ai-engineer',
    'AI engineer path covering practical AI product development, Python, ML foundations, LLMs, RAG, agents, evaluation, safety, LLMOps, deployment, observability, and portfolio-ready AI systems.',
    'Artificial Intelligence',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'ai-engineer'), inserted_roadmap AS (
    SELECT career_role_id, 'AI Engineer Roadmap', 'A structured learning path for becoming an AI engineer, covering practical AI product development, Python foundations, machine learning, deep learning, large language models, prompt engineering, retrieval-augmented generation, agents, evaluation, safety, LLMOps, deployment, observability, and portfolio-ready AI systems.', 'template', 'static', 'public' FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT roadmap_id, 1, 'published', 'AI Engineer Roadmap v1', 'A practical AI engineering roadmap that moves from foundations to production-ready AI applications through guided topics, checkpoints, optional practice projects, and required milestone projects.', 460, 'none', '{}'::jsonb, 'TB', 'custom', now() FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;






