('proj-ai-copilot-feature', 'ph-ai-app-engineering', 91, 'project', NULL, NULL, NULL, 'Optional AI Copilot Feature', 'Optional practice project: Add an AI copilot feature to an existing app with streaming UX, feedback capture, and prompt versioning.', 'This project gives learners a concrete way to practice AI Application Engineering by producing an working AI Copilot Feature notebook, service, or app with evaluation notes. The artifact is intended for review and reflection, not as proof of mastery or job readiness.', 'side', 'ph-ai-app-engineering-projects', 7, 91, 10, 'intermediate', 35, 280, 11830, '{"project":true,"projectBrief":"Add an AI copilot feature to an existing app with streaming UX, feedback capture, and prompt versioning.","projectKind":"ai_ml_application","projectScope":"small_practice_artifact","projectPurpose":"Practice the surrounding roadmap segment through a small reviewable artifact.","phaseContext":"AI Application Engineering","deliverable":"an working AI Copilot Feature notebook, service, or app with evaluation notes","skillsToPractice":["AI Application Engineering"],"suggestedSteps":["Define the AI Copilot Feature scenario and list the specific items to demonstrate: prompt versions and outputs.","Choose the dataset, model, prompt, retrieval source, or tool boundary required by the project brief.","Build the baseline workflow first, then add the AI/ML behavior in a way that can be inspected.","Capture evaluation cases that include successful output, weak output, and at least one failure mode.","Add safeguards, citations, metrics, traces, or manual review notes where the project context requires them.","Document model assumptions, limitations, cost/latency concerns, and what would need review before real use."],"expectedEvidence":["an working AI Copilot Feature notebook, service, or app with evaluation notes.","README or notes that explain setup, usage, assumptions, and expected output.","Evaluation cases, model/prompt/retrieval configuration, and notes on weak or unsafe outputs.","Validation evidence such as tests, screenshots, logs, query results, metrics, traces, or review notes.","Short reflection on trade-offs, limitations, and one reasonable next improvement."],"reviewFocus":["Does the artifact directly match the project brief?","Can another person run, inspect, or review the result from the provided notes?","Are assumptions, limitations, and trade-offs stated clearly?"],"scopeGuardrails":["Keep the implementation focused on the stated project brief.","Prefer a complete small artifact over a broad unfinished system.","Treat completion as reviewable evidence, not a certification claim."],"claimLimit":"Completion creates reviewable project evidence. It does not certify mastery or guarantee job readiness.","evidenceRequired":true,"optionalPractice":true,"milestone":false,"source":"roadmap.sh/ai-engineer","nodeKey":"proj-ai-copilot-feature"}'::jsonb, false, true, '["Apply AI Application Engineering through a focused AI Copilot Feature artifact.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The an working AI Copilot Feature notebook, service, or app with evaluation notes is available for review.","The AI Copilot Feature scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness."]'::jsonb),
('chk-ai-app-review', 'ph-ai-app-engineering', 99, 'checkpoint', 'review', NULL, NULL, 'AI Application Design Review', 'Review checkpoint for AI Application Engineering. The learner synthesizes completed topics such as FastAPI for AI Apps, Request Validation, Streaming Endpoints, Background Jobs, records evidence, and updates the learning plan before continuing.', 'This checkpoint turns the phase boundary into a reflection and evidence-review step for the AI engineering roadmap rather than another unchecked content topic.', 'checkpoint', 'ph-ai-app-engineering-checkpoints', 7, 99, 2, 'intermediate', 65, 280, 12550, '{"checkpoint": true, "source": "roadmap.sh/ai-engineer", "nodeKey": "chk-ai-app-review", "checkpointPurpose": "phase_review", "reviewMode": "review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Explain how topics from AI Application Engineering connect to realistic AI engineering work.", "Select evidence that shows attempted practice, reasoning, or implementation decisions.", "Identify which topics need review before moving to later roadmap areas."]'::jsonb, '["Write a concise review of the main ideas from this segment.", "Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.", "Record open questions, weak areas, or follow-up actions.", "Mark the checkpoint complete only after the review artifact and next steps are captured."]'::jsonb),
