('ms-required-ai-capstone', 'portfolio-interview-readiness-and-capstone', 91, 'project', NULL, NULL, NULL, 'Required AI Engineering Capstone', 'Capstone project: Build a portfolio-grade AI application with RAG or agents, evals, safety controls, deployment, monitoring, and a clear technical case study.', 'This project gives learners a concrete way to practice Portfolio, Interview Readiness, and Capstone by producing an portfolio-ready AI Engineering Capstone case study and integrated artifact. The artifact is intended for review and reflection, not as proof of mastery or job readiness.', 'side', 'ph-portfolio-capstone-projects', 13, 91, 24, 'advanced', 70, 280, 14950, '{"project":true,"projectBrief":"Build a portfolio-grade AI application with RAG or agents, evals, safety controls, deployment, monitoring, and a clear technical case study.","projectKind":"portfolio_capstone","projectScope":"portfolio_capstone","projectPurpose":"Integrate several roadmap areas into a portfolio-ready case study.","phaseContext":"Portfolio, Interview Readiness, and Capstone","deliverable":"an portfolio-ready AI Engineering Capstone case study and integrated artifact","skillsToPractice":["Technical Case Studies","Portfolio Communication","Career Planning","Model Evaluation","Responsible AI and Governance"],"suggestedSteps":["Define the AI Engineering Capstone scenario and list the specific items to demonstrate: retrieval and citations, monitoring signals.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"expectedEvidence":["an portfolio-ready AI Engineering Capstone case study and integrated artifact.","README or notes that explain setup, usage, assumptions, and expected output.","Case study page or write-up that connects the artifact to role-relevant decisions and evidence.","Validation evidence such as tests, screenshots, logs, query results, metrics, traces, or review notes.","Short reflection on trade-offs, limitations, and one reasonable next improvement.","Architecture, review checklist, and limitation section suitable for portfolio discussion."],"reviewFocus":["Does the artifact directly match the project brief?","Can another person run, inspect, or review the result from the provided notes?","Are assumptions, limitations, and trade-offs stated clearly?"],"scopeGuardrails":["Keep the implementation focused on the stated project brief.","Prefer a complete small artifact over a broad unfinished system.","Treat completion as reviewable evidence, not a certification claim."],"claimLimit":"Completion creates reviewable project evidence. It does not certify mastery or guarantee job readiness.","evidenceRequired":true,"optionalPractice":false,"milestone":true,"source":"roadmap.sh/ai-engineer","nodeKey":"ms-required-ai-capstone"}'::jsonb, true, true, '["Apply Technical Case Studies, Portfolio Communication, Career Planning through a focused AI Engineering Capstone artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The an portfolio-ready AI Engineering Capstone case study and integrated artifact is available for review.","The AI Engineering Capstone scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb),
('proj-ai-interview-pack', 'portfolio-interview-readiness-and-capstone', 92, 'project', NULL, NULL, NULL, 'Optional AI Interview Pack', 'Capstone project: Prepare architecture diagrams, tradeoff notes, failure-mode explanations, and concise project walkthroughs.', 'This project gives learners a concrete way to practice Portfolio, Interview Readiness, and Capstone by producing an portfolio-ready AI Interview Pack case study and integrated artifact. The artifact is intended for review and reflection, not as proof of mastery or job readiness.', 'side', 'ph-portfolio-capstone-projects', 13, 92, 8, 'advanced', 35, 280, 15040, '{"project":true,"projectBrief":"Prepare architecture diagrams, tradeoff notes, failure-mode explanations, and concise project walkthroughs.","projectKind":"portfolio_capstone","projectScope":"portfolio_capstone","projectPurpose":"Integrate several roadmap areas into a portfolio-ready case study.","phaseContext":"Portfolio, Interview Readiness, and Capstone","deliverable":"an portfolio-ready AI Interview Pack case study and integrated artifact","skillsToPractice":["Career Planning"],"suggestedSteps":["Define the AI Interview Pack scenario, target user or reviewer, and the specific Portfolio, Interview Readiness, and Capstone concepts it will demonstrate.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"expectedEvidence":["an portfolio-ready AI Interview Pack case study and integrated artifact.","README or notes that explain setup, usage, assumptions, and expected output.","Case study page or write-up that connects the artifact to role-relevant decisions and evidence.","Validation evidence such as tests, screenshots, logs, query results, metrics, traces, or review notes.","Short reflection on trade-offs, limitations, and one reasonable next improvement.","Architecture, review checklist, and limitation section suitable for portfolio discussion."],"reviewFocus":["Does the artifact directly match the project brief?","Can another person run, inspect, or review the result from the provided notes?","Are assumptions, limitations, and trade-offs stated clearly?"],"scopeGuardrails":["Keep the implementation focused on the stated project brief.","Prefer a complete small artifact over a broad unfinished system.","Treat completion as reviewable evidence, not a certification claim."],"claimLimit":"Completion creates reviewable project evidence. It does not certify mastery or guarantee job readiness.","evidenceRequired":true,"optionalPractice":true,"milestone":false,"source":"roadmap.sh/ai-engineer","nodeKey":"proj-ai-interview-pack"}'::jsonb, false, true, '["Apply Career Planning through a focused AI Interview Pack artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The an portfolio-ready AI Interview Pack case study and integrated artifact is available for review.","The AI Interview Pack scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb),
('chk-final-review', 'portfolio-interview-readiness-and-capstone', 99, 'checkpoint', 'gate', NULL, NULL, 'Final AI Engineering Review', 'Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the AI engineering path.', 'This checkpoint closes the suggested AI engineering orientation path by organizing evidence and next steps. It is not an employment guarantee or formal competency certification.', 'checkpoint', 'ph-portfolio-capstone-checkpoints', 13, 99, 2, 'advanced', 65, 280, 15670, '{"checkpoint": true, "source": "roadmap.sh/ai-engineer", "nodeKey": "chk-final-review", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent AI engineering learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb)
;

SELECT m.roadmap_version_id, NULL, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn CROSS JOIN seed_roadmap_map m
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

UPDATE public.roadmap_node child
SET parent_node_id = parent.roadmap_node_id
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node parent ON parent.roadmap_version_id = m.roadmap_version_id AND parent.slug = sn.parent_key
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NOT NULL;

UPDATE public.roadmap_node child
SET parent_node_id = NULL
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NULL;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL, skill_slug text NOT NULL, PRIMARY KEY (node_key, skill_slug)) ON COMMIT DROP;


